INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (14992,'com1','김선기','spsp99@naver.com','수학 학습봉사자 모집','중2 남 아동 1명 수학을 가르쳐주실 자원봉사자를 모집합니다. <br><br>기초부터 학습이 필요합니다. <br><br>아동에 관심있고 6개월 이상 꾸준하게 봉사해주실 선생님은 상담해주시기 바랍니다. <br><br>자세한 내용은 첨부파일을 확인하여주시기 바랍니다. <br>          </td>
