INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (14544,'com1','호선생','','사회사복시자격증 단기 취득가능','-안녕하세요~ 교육원 인가 학습멘토 호선생입니다.<br>요즘 누구나 꿈꾸는 자격증이 바로 사회복지사 인데요.<br>전망도 좋고 쉽게 취득하실수 있기에 많은 사람들이 원하시는 자격증 중 하나입니다<br>그럼 사회복지사에 대해서 한번 알아 볼까요?<br><br>◑ 사회복지사2급<br><br><br><br>※ 무시험으로 과목 이수 후 자격증 취득 ※<br><br><br>-------------------------------------------------------------------------<br><br><br>▶집에서 동영상 강의만 듣고 시험없이 국가자격증 취득!<br><br>▷동영상 강의 재생, 일시정지 마음대로!<br><br>▶주말, 공휴일 상관없이 강의 듣기!<br><br>▷정해진 시간, 장소없이 언제 어디서나!<br><br><br><br><br>◑◑◑◑◑◑◑◑◑ 사회복지사2급 ◐◐◐◐◐◐◐◐◐<br><br> 이론 13과목 + 실습 1과목 <br>(보육교사 중복과목으로 병행 추천)<br><br><br>* 실습 인계!<br><br> 실습이 연결되지 않는 문제없이<br> 사회복지사2급 자격증 취득<br><br><br> ●고졸 : 사회복지사자격증 + 전문대 졸업장 ( 교육부 장관 명의 )<br>          <br>          기간 - 1년 6개월<br>26온라인 이수과목 + 1개 실습과목<br><br> ●대졸 : 전공 상관없이 취득 가능<br> <br>          기간 - 1년<br>13온라인 이수과목 + 1개 실습과목<br><br><br>* 무시험으로 취득하는 국가공인자격증!<br><br> - 현재는 시험없이 100% 온라인 수업만으로 취득<br> - 남,녀,노,소 없이<br> - 학력, 학벌, 경력, 전공 등 상관없이<br> - 강의만 들으면 취득<br><br><br> 개정안 시행 후,<br> 국가고시 시험을 통과해야 취득<br><br> 시험없이 인터넷으로 동영상 강의만으로 <br> 취득 할 수 있는 마지막 기회!<br><br><br> 게.다.가.<br> 1:1 관리 해주는 담당 멘토까지!<br><br><br><br>※ 현재 진행중인 장학 할인 행사 ※<br><br>수강생분들 중 선착순에 한해<br>장학 할인 혜택 적용으로<br><br>절반 이상의 비용 지원!<br><br><br><br><br><br><br>-----------------------------------------------------------------<br><br><br><br>시간, 장소 제약없이!<br><br>직장인, 주부 상관없이 누구나!<br><br>난이도 쉬운 동영상 강의로 자격증 취득!<br><br>어떤 시험없이 단기간에 취득하는 국가공인자격증!<br><br><br><br>-----------------------------------------------------------------<br><br><br><br><br><br><br><br>◑◑◑◑◑◑ 개인 멘토의 체계적인 학습 관리 ◐◐◐◐◐◐<br><br>정식으로 인정 받은 교육원에서<br>1:1 개인 관리를 해드리는 담당 멘토와 학습!<br><br>회원가입부터 수강신청,<br>이후 학습 일정 등 추후 관리까지<br><br> <br><br><br>★★★ 주말, 공휴일 없이 연중휴무 ★★★<br>    <br>   ★★★ 24시간 1:1 개인 상담 ★★★<br><br><br>           전화 &amp; 문자 상담<br>           - O1O - 3676 - 8591<br><br><br>          카카오톡 상담<br>          - yuh9094          </td>
        </tr>',1236,1465830000,'', '', '', '', '', '');
