INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (13351,'com1','방혜영','roomhy@naver.com','기증 문의드립니다','막달 태아가 하늘나라로 가게되어 아이를 위해 준비했던 유모차를 뜻깊은 곳에 쓰고자 합니다.<br>혹시 기증할 방법이 있는지 안내해주시면 감사드리겠습니다.<br><br>연락처: 010-5255-9726          </td>
