INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (13340,'com1','이재웅','capwoong79@gmail.com','학습 봉사자 선생님을 초대합니다.','아동복지시설 남산원은 <br><br>초등학교 6학년(남) 수학과 미취학 아동(남) 3명에게 한글을 가르쳐 주실 자원봉사자을 초대합니다. <br><br>아동에 관심있고 6개월 이상 꾸준하게 봉사해주실 선생님은 상담해주시기 바랍니다.          </td>
