INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (13232,'com1','관리자','test@test.com','봉사활동 협의','마음 정성 고맙습니다.<br>이곳은 청소년시설이고 또래아이들이 많이 생활하고 있습니다.<br>그래서 연락안드렸으니, 학생들이<br>봉사활동 할 수 있는곳을 알아보시기 바랍니다.<br>감사합니다.          </td>
        </tr>',1148,1446476400,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (12940,'com1','서울시사회복지협의회','energyseoul@naver.com','에너지복지시민기금 마련을 위한 남산걷기대회에 초대합니다!','에너지복지시민기금 마련을 위한 남산걷기대회에 초대합니다!<br><br> ○ 일 시 : ’15. 9. 19(토) 08:40~12:00  ※ 출발 9:00<br> ○ 장 소 : 남산 백범광장<br> ○ 참가신청: 모바일서울 앱 또는 http://m.seoul.go.kr/mw/walking/WalkingEnergy.do<br>             ※현장 접수 가능<br> ○ 코 스 : 에너지 나눔길 6km(백범광장→북측순환로 국립극장삼거리(반환점)→북측순환로→백범광장)<br> ○ 봉사활동: VMS(사회복지자원봉사인증) 봉사활동 신청<br> ○ 주요내용<br>    - 에너지 나눔 걷기대회 6km<br>     ▸ 백범광장 → 북측순환로 → 국립극장삼거리(반환점) → 북측순환로 → 백범광장  <br>    - 서울에너지복지시민기금 시민참여 캠페인, 원전하나줄이기 체험 등<br>       ※ 한국일보에서 참여시민 당 1천원 에너지복지시민기금으로 기부예정<br>    - 굿바이 백열등 +나눔 캠페인 추진<br>       (백열등을 하나 가져오면 LED전등으로 교체해주고 +하나는 에너지빈곤층에 기부하는 캠페인)<br>    - 에너지나눔 동전밭<br>       (집에서, 사무실에서, 주머니에서 잠자고 있는 동전을 에너지빈곤층에 기부하는 캠페인)<br><br>  ○ 경 품 : LED TV, 듀얼 LED램프, 무선 진공청소기, 전기압력밥솥, 트레킹화 등<br>  ○ 주 최 : 한국일보, 서울에너지복지시민기금<br>  ○ 후 원 : 서울시, 포스코에너지, 필립스, 코리아세븐<br>  ○ 문 의 : 서울에너지복지시민기금 담당자 02-2021-1750<br>            한국일보 02-724-2260/ www.hkturtle.com<br><br>          </td>
        </tr>',2454,1442156400,'걷기대회 개요(최종).pdf', '', '', '걷기대회 개요(최종).pdf', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (12701,'com1','관리자','test@test.com','학습 특기적성 자원봉사 선생님 초대합니다.','아동복지시설 남산원은 학습 특기적성 자원봉사를 꾸준하게 해주실 선생님을 초대합니다.<br><br>관심있고 6개월 이상 꾸준하게 봉사해주실 선생님은 상담해주시기 바랍니다. <br>          </td>
        </tr>',1107,1438009200,'※ 학습 특기적성 봉사자 모집.hwp', '', '', '※ 학습 특기적성 봉사자 모집.hwp', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (12803,'com1','최호용','','봉사 문의드립니다.','안녕하세요. <br><br>즐봉이라는 봉사 동아리입니다.<br><br>한달에 한번 정기적으로 토요일날 봉사활동을 하고 싶습니다. <br><br>시간은 12시~13시 부터 17시~18시까지 <br><br>정기적으로 봉사가 가능한지 문의드립니다.<br><br>현재 동아리 인원은 20명이며, <br><br>매달 7명~12명정도 정기적으로 봉사가 가능할거 같습니다. <br><br>          </td>
        </tr>',1056,1439823600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (12310,'com1','최훈임','','봉사문의','안녕하세요 ! <br>아기돌보는 봉사에 대해 문의 드릴 것이 있어서 글을 남깁니다.^^<br>제가 봉사를 시작하게 되면 8~9월달까지만 할 수가 있어서요..<br>혹시 가능한지, 또 신청은 어떻게 해야 하는건지 궁금해서요.<br>답변 부탁드릴께요^^ 그럼 좋은하루 보내세요!          </td>
        </tr>',1097,1430146800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (12093,'com1','김효진','siria0821@empal.com','아기옷 후원하고 싶은대요..','<br>안녕하세요? 두돌지난 딸을 두고 있는 아기엄마입니다.<br><br>아이를 키우다보니 다른아이들의 아픔도 생각하게 되네요.<br><br>첫아이고 외동이라 새옷을 사서 입혔지만..아기때는 젖을 자주 올려서 지저분한곳도 있고<br><br>깨끗한 옷도 있습니다.<br><br>중고옷파는데에 팔수도 있지만.. 그보다 더 뜻깊은 일을 하고 싶습니다.<br><br>젖올린 옷은 혹시 실례가 될까바 미리 여쭤보려구요..(브랜드있는옷들인대 얼룩땜에 버리긴 아까워서요..)<br><br>제가 둘째를 낳을꺼면 물려서 입히겠는데 전 하나만 낳을꺼라서요..<br><br>24개월 이전 아이들이 혹 없을까바도 걱정되구요..<br><br>          </td>
        </tr>',1303,1425999600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (12345,'com1','김소연','sherlykim94@naver.com','봉사신청','봉사 신청위해서 전화드려도 안받으시고..인터넷 신청도 했는데 연락이 없으셔서요ㅠㅠ..꼭 하고 싶어요 연락주세요..<br>01033602536          </td>
        </tr>',1226,1431097200,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (11543,'com1','이솔교육c','','(장학교육비 전액지원)미술심리상담사/심리상담사 지원안내','(장학교육비 전액지원)미술심리상담사/심리상담사 지원안내<br><br>◆ 미술심리상담사/심리상담사 과정안내<br><br>저희 이솔교육에서는 심리상담사와 미술심리상담사 과정에 대하여 교육비전액지원 혜택과 함께 실무중심 전문가들의 알찬 강의를 통하여 자격증 취득을 도와드리고 있습니다.<br><br><br>1. 자격조건 : 누구나 지원가능<br><br><br>2. 교육비   : 무료(100% 교육비 지원)<br><br><br>3. 수강기간 : 5주<br><br><br>4. 교육과정안내 : 온라인교육 (인터넷강의)<br><br><br>   미술심리상담사 : 총 39강(강의당 약 25분) / 고은영, 조정용, 이미란 교수님<br> <br>   심리상담사     : 총 39강(강의당 약 25분) / 윤미자, 김현미 교수님<br><br><br><br>◆ 학교폭력/성폭력 예방 지도사 과정안내 (교육비 70% 할인혜택 제공)<br><br><br>1. 자격조건  : 누구나 지원가능<br><br><br>2. 교육비    : 과정당 580,000원 --&gt; 과정당 174,000원 (교육비 70% 할인지원)<br><br><br>3. 수강기간  : 8주<br><br><br>4. 교육과정안내  : 온라인교육(인터넷강의) - &lt;자막지원서비스 가능&gt;<br><br>   학교폭력예방지도사  : 총 45강(강의당 약 25분) / 이태호, 신동열, 박재원 교수님 등<br><br>   성폭력예방지도강사  : 총 45강(강의당 약 25분) / 조인섭변호사, 홍순기, 소은희 원장님 등<br><br><br><br>★ 신청방법 안내<br><br>    https://docs.google.com/forms/d/1E7Aw7axi_RSXT_InUQJ5XSNz0Ky4iHD3TCKwWn09RkA/viewform?usp=send_form<br>   위의 링크주소로 접속하셔서 신청서 작성후 보내기버튼을 클릭하여 주시면 됩니다. <br>    <br><br>★  신청시 궁금한점은  유선으로 문의하여 주시면 신속하게 도와드리겠습니다.<br><br><br>★  심리상담사/미술심리상담사 과정은 복수지원하셔도 무상지원이 가능합니다.<br><br><br>★  시험은 4주이상(진도율 80%) 수강하면 종강전까지 상시가능하며 빠른 취득을 할 수 있습니다.<br><br><br>★  저희 이솔교육의 모든 교육과정은 한국직업능력개발원에 정식등록 된 과정입니다.<br><br><br>★  수강 중 불편사항이 발생하시면 원격지원으로 원활한 수강을 도와드리겠습니다.<br><br><br><br>문의사항이 있으시면 언제든지 대표전화 [02-744-9409] 으로 전화 주시면 친절하게 안내해드리겠습니다.<br><br>☎ 02-744-9409/ 홈페이지 : www.esoledu.or.kr <br> (주소: 서울시 중랑구 묵동 163-3번지 태양빌딩 3층)  <br><br><br>----&gt; 신청서 https://docs.google.com/forms/d/1E7Aw7axi_RSXT_InUQJ5XSNz0Ky4iHD3TCKwWn09RkA/viewform?usp=send_form<br>      <br>       <br>     - 위 링크로 접속이 안될경우 신청서(첨부파일)를 다운받아, 교육비지원과정 신청서 작성 후 <br>팩스02)744-9409 전송하거나, esoledu1004@naver.com 메일로 보내주시기 바랍니다. <br>- 신청서 및 기타 문의는 ☎02)744-9409 이솔교육평생교육원으로 전화주시기 바랍니다. <br><br><br><br>신청서완료후 이솔교육회원가입-수강신청 완료 되시면 이번호로 다시연락 부탁드립니다.          </td>
        </tr>',1277,1416754800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (11768,'com1','오유경','duckqq560@naver.com','보육교사 자격증? 사회복지사 자격증 취득!','안녕하세요. 현대 사이버 평생교육원 오유경팀장 입니다^_^<br><br><br><br>사회복지사 2급 자격증 , 보육교사 2급자격증 국가시험이 현재로선 시험 없이 온라인강의를통해서 집에서 수월하게 취득할 수가 있어요~<br><br><br>하지만, 앞으로는 시험제도가 변경된다는 확정이 되었기에 하루 빨리 취득 하시는것이 관심있으신분들에게 <br><br>효율적인 정보가 되지 않을까 해서 글을 남깁니다^^<br><br><br><br>- 사회복지사 2급 자격증 취득 과정과 시간<br><br>▶총 14과목을 수강 하시면 자격증 취득이 가능 하세요 <br><br>(온라인강의 13과목  + 실습1과목) 취득과정은 2학기플랜(1년과정) 이면 취득 가능하세요~<br><br><br><br>- 보육교사 2급 자격증 취득 과정과 시간<br><br>▶총 17과목을 수강 하시면 취득이 가능 하세요<br><br>(온라인강의 16과목 + 실습1과목) 취득기간은 3학기플랜(1년6개월)이면 취득 가능하세요~<br><br><br><br><br>저희 교육원은 1:1 담당플래너 체제로서 학생분들 한 분, 한 분 개인으로 맞아 자격증 취득 하는 날 까지 관리를 도와드리기 때문에<br><br>어려운부분없이, 나이에 상관없이, 직업에 상관없이 누구나 취득 가능 하시구요~<br><br>시험난이도 또한 다른 교육원에 비해 매우 쉬운편이기때문에 공부하시는거에 대해서 부담 없이 진행이 가능 하십니다^_^<br><br><br><br>저희 교육원은 현대직업전문학교를 가지고있는  교육원 이기 때문에 실습대학연계또한 수월하게 진행 가능 하시구요..<br><br><br><br><br>★2015년도 1학기 수강생들 혜택★<br><br><br><br>수강료가 과목당 40% 할인 이벤트 진행이 들어 가세요 ^_^<br><br>타 교육원에서 한과목당 15~30만원에 수강하셔야 하는 민간자격증또한 갯수에 상관없이 무료수강 가능하세요 ^_^<br><br>교육원 선택에 앞서 가장 중요하신 부분은 교육과학기술부에 인가를 받은기관인지, <br><br>1:1 관리가 철저하게들어가는지 확인을 하셔야합니다!<br><br><br><br><br>♥인가받은교육기관 현대 사이버 평생교육원 오유경팀장 이었습니다!♥<br><br><br>☎전화 : 010-2042-2540<br><br>☏카카오톡 : duckqq560<br><br>☎네이트온 : duckqq560@nate.com<br><br>☏이메일 : duckqq560@naver.com          </td>
        </tr>',1065,1420383600,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (11527,'com1','김관영','passwordz@naver.com','자원봉사 하고 싶습니다','안녕하세요 37살 도봉동 사는 김관영입니다.<br><br>자원봉사를 지원합니다.<br><br>시간은 토요일 오전(9시~12시)으로 생각하고 있습니다.<br><br>식판닦기나 청소등. 간단한것부터 시작하고 싶은데요~ <br><br>연락부탁드립니다. 01023298059 김관영          </td>
        </tr>',1444,1416582000,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (11500,'com1','이에듀케이션','','■[교육부 정식인가]상담사,지도사 자격증 무료수강- 12월7일까지■','○ 모집개요<br>- 유망 자격증 교육문화를 선도하는 이에듀케이션 평생교육원에서는 교육과 자격증이 경쟁력이 되는 시대에 누구나, 언제, 어디서나, 교육 받고 자격증을 취득 할 수 있는 평생학습사회, 열린교육 학습시대를 만들고자 하는 시대를 열기 위해 전문자격증 과정을 무상제공 및 장학혜택을 드리고자 합니다. ※모든 자격증은 한국직업능력개발원 http://www.pqi.or.kr에 등록된 공신력 있고 합법적인 자격증입니다.<br><br>○ 접수기간<br>- 2014년 11월 1일(토) ~ 2014년 12월 7일(일) 까지<br><br>○ 혜택내역<br>[무료장학지원과정]<br>- 수강료100%전액장학지원과정 과목당: 수강료 400,000원&gt;&gt;&gt;전액장학지원 무료, 총 9개 과정<br>-최대 3과목까지 신청가능&amp;교재무료제공<br><br>1. 도형심리상담사 <br>2. 심리상담사 <br>3. 자기주도학습지도사 <br>4. 진로코칭지도사<br>5. 교류분석사<br>6. 학교폭력예방상담사  <br>7. 미술심리상담사<br>8. 방과후 지도사 <br>9. 음악심리상담사<br><br>○ 접수방법<br>- 첨부된 이에듀케이션 수강신청서 작성 후 이메일이나 팩스로 접수<br>- 수강신청 메일 : myjiin@e-education FAX : 02-928-2999<br>- 수강신청서가 다운이 안 되시는 분들은 메일로 요청하시면 수강신청서를 보내드립니다.<br><br>○ 지원자격<br>- 만20세이상 성인 [대학생, 일반인, 개인기업체, 관공서등 참가 가능] <br>- 과정별 500명이내 선착순 [수강신청지원자]<br><br>※ 각 과목마다 제한인원이 있어서 신청서 접수 후 수강 반에 못 들어갈 수 있으며, 결과는 개별 통보해드립니다.<br>※ 장학지원이벤트 기간이 끝나면 모든 과정은 유료로 진행되오니 이점유의하시기 바랍니다.<br><br>○ 유의사항<br>- 수강기간 : 과정별 3~6주 과정<br>- 개강일 : 11월 4일, 11일 18일, 25일<br>- 강의교재 : 강의교안파일 무료제공(단, 아동심리상담사, 인성지도사, 심리분석사 희망시 구매)<br>- 강의방법 : 온라인 강의<br>- 시험예상기출문제 제공<br><br>[자격증 발급 신청 시]<br>- 자격증 발급 조건 : 출석률 70%이상 + 시험성적 60점 이상<br>- 온라인 시험이 끝난 후 자격증 발급신청 기간: 2주<br>- 수강 완료 후 자격증 발급 시 발급 비용은 개별부담<br><br>○ 문의<br>- 이 에듀케이션<br>- 홈페이지 :http://www.e-education.co.kr/<br>- 담당부서 : 교육지원부<br>- 문의처 : tell:02-928-1300<br>- 이메일 : myjiin@e-education.co.kr<br><br>          </td>
        </tr>',939,1416236400,'수강신청서.hwp', '', '', '수강신청서.hwp', '', '');
