INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (11385,'com1','노수정','','주님의 이름으로 용서하시고 사랑합니다..시급합니다.','샬롬.<br><br>얼굴을 뵌적은 없지만 주님안에서 하나이기에 맘과 맘이 통할것을 믿으며 글을 올립니다.<br><br>지금 한국에 전쟁이 곧 있을거란 소식이 안밖으로 들리고 있습니다.<br><br>물론 거짓예언도 많았고 거짓선지자들의 미혹도 많았습니다.<br><br>하지만 지금은 좀 다릅니다.<br><br>몇몇 선교사님과 목사님들의 예언을 통해 전국적으로 회개운동이 일어나고 있습니다.<br><br>우선...주님앞에 회개합니다.<br><br>내아이 먹일생각만했고 말로만 주님사랑한다 해놓고 이웃사랑 하지 못했음을 용서해주세요.<br><br>버림받고 가장 차가운곳에 있었던 아이들을 주님의 맘으로 품지못함을 용서해주세요..<br><br>  &lt;o:p&gt;&lt;/o:p&gt;<br><br>그러기에 간절한 맘으로 호소합니다.<br><br>전쟁메세지를 들으시고 아이들과 함께 거처를 마련하시길 소망합니다.<br><br>그리고 아이들모두 세례받길 소망합니다.<br><br>저 역시 두아이의 엄마로써 이제야 이곳 아이들이 제 아이임을 깨달으며 밤잠지새우며 중보기도하겠습니다..<br><br>부디 주님의 인도하심이 있길 기도드립니다.<br><br>전국적으로 땅굴사실밝히기를 하고 있으나 종북세력에 의해 막히고 있습니다.<br><br>나라를 위해서도 기도부탁드립니다.<br><br> <br><br>http://www.youtube.com/watch?v=lVdDxKzMDoI&amp;feature=player_embedded<br>          </td>
        </tr>',1442,1414508400,'', '', '', '', '', '');
