INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (11029,'com1','박소연','soyoen5679@naver.com','봉사활동 문의드립니다.','안녕하세요.<br>혹시 9월 아가방봉사 신청으로 하려고 하는데<br>절차서가 따로 어디에있는지 찾지를 못하겠어서요..<br>제가 이 사이트는 지금 처음이라<br>어떻게 하는지 상세하게 알려주시면 감사하겠습니다!          </td>
