INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (10976,'com1','Anna','','안녕하세요? 지인의 소개로 알게 되었어요.','그래서 제가 뭘 할 수 있을까 홈피를 둘러보던 중에 살작 걱정이 되어서 글을 쓰게 되었어요.<br><br>아이들 얼굴이 너무 그대로 다 나오는데 걱정이 됩니다<br><br>세상이 너무 흉흉하고, 초상권도 있는데요.<br><br>꼭 나와야 하는 피치못할 이유가 있는 건지요?<br><br>애쓰시는 훌륭한 분들께 제가 보자마자 이런말씀을 드려서 죄송하지만,<br><br>걱정돼요.          </td>
        </tr>',1510,1408546800,'', '', '', '', '', '');
INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (10932,'com1','정우진','skylover072@naver.com','봉사활동 문의드립니다.','안녕하세요? 직장 다니는 24세 여자 직장인입니다. 영아방 봉사활동 관심 있어서 글을 남깁니다.<br><br>홈페이지는 관련 지원부분이 없어 보이는데 혹시 어떻게 지원하면 되는지요?<br><br>답변 기다리겠습니다. 감사합니다 ^^          </td>
