INSERT INTO `wiz_bbs` (`idx`,`code`,`name`,`email`,`subject`,`content`,`count`,`wdate`,`upfile1`,`upfile2`,`upfile3`,`upfile1_name`,`upfile2_name`,`upfile3_name`) VALUES (10739,'com1','김은지','k58895@nate.com','문의드립니다.','안녕하세요.<br>채용 문의드립니다<br>자격증이 필요하나요?<br>아이들을 좋아해서 이 일을 하고싶은데요<br>답변 부탁드립니다.<br>          </td>
